// Calcula since/until = ultimos 30 dias (UTC).
const toDate = new Date();
toDate.setUTCDate(toDate.getUTCDate() - 1);
const fromDate = new Date(toDate);
fromDate.setUTCDate(fromDate.getUTCDate() - 29);
const toIso = toDate.toISOString().slice(0, 10);
const fromIso = fromDate.toISOString().slice(0, 10);
const sinceUnix = Math.floor(fromDate.getTime() / 1000);
const untilUnix = Math.floor((toDate.getTime() + 86400000) / 1000);
return [{ json: { from: fromIso, to: toIso, since: sinceUnix, until: untilUnix } }];

// Normaliza FB Page insights → meta_page_daily.
// Input: { data: [{ name, period, values: [{ value, end_time }, ...] }, ...] }
const pageId = 'REPLACE_PAGE_ID';
const out = new Map();
const input = items[0]?.json || {};
const metrics = input.data || [];
for (const m of metrics) {
  const name = m.name;
  for (const v of m.values || []) {
    const fecha = (v.end_time || '').slice(0, 10);
    if (!fecha) continue;
    let row = out.get(fecha);
    if (!row) {
      row = {
        fecha,
        page_id: pageId,
        impressions: 0,
        impressions_unique: 0,
        engaged_users: 0,
        post_engagements: 0,
        page_views: 0,
        fans_total: null,
        consumptions: 0,
        video_views: 0,
      };
      out.set(fecha, row);
    }
    const val = typeof v.value === 'number' ? v.value : 0;
    if (name === 'page_impressions') row.impressions = val;
    else if (name === 'page_impressions_unique') row.impressions_unique = val;
    else if (name === 'page_engaged_users') row.engaged_users = val;
    else if (name === 'page_post_engagements') row.post_engagements = val;
    else if (name === 'page_views_total') row.page_views = val;
    else if (name === 'page_fans') row.fans_total = val;
    else if (name === 'page_consumptions') row.consumptions = val;
    else if (name === 'page_video_views') row.video_views = val;
  }
}
return [...out.values()].map(json => ({ json }));

// Normaliza IG daily insights → meta_ig_daily.
// Combina output de "IG Daily Insights" y "IG Follower Count" (vienen en
// items separados porque follower_count solo admite metric_type=total_value
// en API moderna; lo separamos para evitar fallos parciales).
const igId = 'REPLACE_IG_USER_ID';
const out = new Map();
const allItems = items.map(i => i.json);
for (const input of allItems) {
  const metrics = input.data || [];
  for (const m of metrics) {
    const name = m.name;
    for (const v of m.values || []) {
      const fecha = (v.end_time || '').slice(0, 10);
      if (!fecha) continue;
      let row = out.get(fecha);
      if (!row) {
        row = {
          fecha,
          ig_user_id: igId,
          reach: 0,
          impressions: 0,
          follower_count: null,
          profile_views: 0,
          website_clicks: 0,
          email_contacts: 0,
          phone_call_clicks: 0,
        };
        out.set(fecha, row);
      }
      const val = typeof v.value === 'number' ? v.value : 0;
      if (name === 'reach') row.reach = val;
      else if (name === 'impressions') row.impressions = val;
      else if (name === 'follower_count') row.follower_count = val;
      else if (name === 'profile_views') row.profile_views = val;
      else if (name === 'website_clicks') row.website_clicks = val;
      else if (name === 'email_contacts') row.email_contacts = val;
      else if (name === 'phone_call_clicks') row.phone_call_clicks = val;
    }
  }
}
return [...out.values()].map(json => ({ json }));

// Normaliza posts (FB + IG) → meta_posts.
// Input: dos items (FB y IG), cada uno con { data: [...posts] }.
const pageId = 'REPLACE_PAGE_ID';
const igId = 'REPLACE_IG_USER_ID';
const out = [];

for (const item of items) {
  const platform = item.json._platform; // injected by Merge node
  const posts = item.json.data || [];
  for (const p of posts) {
    const insights = (p.insights?.data || []);
    const m = {};
    for (const i of insights) {
      if (Array.isArray(i.values) && i.values.length > 0) {
        m[i.name] = typeof i.values[0].value === 'object' ? Object.values(i.values[0].value).reduce((a, b) => a + (b || 0), 0) : (i.values[0].value || 0);
      }
    }
    if (platform === 'facebook') {
      out.push({
        json: {
          platform: 'facebook',
          post_id: p.id,
          cuenta_id: pageId,
          fecha_post: p.created_time || new Date().toISOString(),
          permalink: p.permalink_url || null,
          message: p.message || null,
          media_type: p.attachments?.data?.[0]?.media_type || null,
          thumbnail_url: null,
          impressions: m.post_impressions || 0,
          reach: m.post_impressions_unique || 0,
          engagement: m.post_engaged_users || 0,
          reactions: m.post_reactions_by_type_total || 0,
          saved: 0,
          video_views: m.post_video_views || 0,
          clicks: m.post_clicks || 0,
          raw: p,
        },
      });
    } else if (platform === 'instagram') {
      out.push({
        json: {
          platform: 'instagram',
          post_id: p.id,
          cuenta_id: igId,
          fecha_post: p.timestamp || new Date().toISOString(),
          permalink: p.permalink || null,
          message: p.caption || null,
          media_type: p.media_type || null,
          thumbnail_url: p.thumbnail_url || p.media_url || null,
          impressions: m.impressions || 0,
          reach: m.reach || 0,
          engagement: m.engagement || 0,
          reactions: 0,
          saved: m.saved || 0,
          video_views: m.video_views || 0,
          clicks: 0,
          raw: p,
        },
      });
    }
  }
}

return out;

// Marca cada item con _platform para que Normalize Posts sepa qué es.
const tagged = items.map(i => ({ json: { ...i.json, _platform: 'facebook' } }));
return tagged;
